    /// <summary>
    /// Wire-nav step of the two-pass populate pattern. Invoked exactly
    /// once by <c>GeoDataInitializer</c> after every catalog's first-pass
    /// static ctor has run. Mutates each timezone's <c>PrimaryCountry</c>
    /// + <c>CoApplicableCountries</c> navs via the friend-assembly
    /// <c>internal set</c> accessors.
    /// </summary>
    internal static void WireNav()
    {
        foreach (var tz in All)
        {
            if (tz.PrimaryCountryIso31661Alpha2Code is { } pcc
                && CountryLookup.ByCode.TryGetValue(pcc, out var primary))
            {
                tz.PrimaryCountry = primary;
            }

            if (tz.CoApplicableCountryIso31661Alpha2Codes.Count > 0)
            {
                var list = new List<Country>(tz.CoApplicableCountryIso31661Alpha2Codes.Count);
                foreach (var cc in tz.CoApplicableCountryIso31661Alpha2Codes)
                {
                    if (CountryLookup.ByCode.TryGetValue(cc, out var country))
                        list.Add(country);
                }

                tz.CoApplicableCountries = list.ToArray();
            }
        }
    }
